const trips = $input.first().json.result || [];
let totalDist = 0, totalIdle = 0, totalDrive = 0, tripCount = trips.length;

for (const t of trips) {
  totalDist += (t.distance || 0) / 1000;
  const idleMatch = (t.idlingDuration || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
  if (idleMatch) totalIdle += (parseInt(idleMatch[1]||0)*60 + parseInt(idleMatch[2]||0));
  const driveMatch = (t.drivingDuration || '').match(/PT(?:(\d+)H)?(?:(\d+)M)?/);
  if (driveMatch) totalDrive += (parseInt(driveMatch[1]||0)*60 + parseInt(driveMatch[2]||0));
}

const estFuel = totalDist * 0.12;
const estCO2 = estFuel * 2.5 / 1000;
const idlePct = (totalIdle + totalDrive) > 0 ? (totalIdle / (totalIdle + totalDrive) * 100).toFixed(1) : '0';

return [{ json: {
  trips: tripCount,
  distKm: Math.round(totalDist),
  estCO2Tonnes: estCO2.toFixed(2),
  estFuelL: Math.round(estFuel),
  idlePct,
  idleMinutes: totalIdle
}}];
